  const now = Date.now();
  if (COLLAB_STORY_LOCKED_CARD_ID === String(cardId) && now - COLLAB_STORY_LOCK_LAST_SEND_MS < 2500) return true;
  COLLAB_STORY_LOCKED_CARD_ID = String(cardId);
