  const labelOptions = (STORY_LABELS[labelGroup] || STORY_LABELS.shot).map(l => `<option value="${escapeStoryAttr(l)}" ${l === card.label ? 'selected' : ''}>${escapeHtml(l)}</option>`).join('');
