function getCurrentLocalCachedSource(){
  return (currentMediaSource && currentMediaSource.type === 'local' && currentMediaSource.cacheId) ? currentMediaSource : null;
}

function rememberLocalCacheFromBackend(data){
  const src = data?.source;
  if (!src || src.type !== 'local_cached' || !src.cache_id) return;
  const curFile = currentMediaSource?.file || lastLoadedVideoFile || fileInput?.files?.[0] || null;
  const mediaPoolKey = currentMediaSource?.mediaPoolKey || '';
  currentMediaSource = {
    type: 'local',
    file: curFile,
    cacheId: String(src.cache_id),
    cacheDir: src.cache_dir || '',
    audioPath: src.audio_path || '',
    filename: src.filename || curFile?.name || 'media',
    duration: Number(src.duration || 0) || 0,
    mediaPoolKey,
  };
  // Propagate the new cache_id back to the matching Media Pool asset so the
  // wiring survives across mode switches (Story Mode → Multi-Timeline → render).
  // Without this, the cache_id lives on currentMediaSource only and the
  // render pipeline can't resolve the asset by media_pool_key.
  try{
    if (mediaPoolKey && Array.isArray(__mediaPoolAssets)){
      const asset = __mediaPoolAssets.find(a => a.media_pool_key === mediaPoolKey);
      if (asset){
        asset.cache_id = String(src.cache_id);
        asset.cacheId = asset.cache_id;
        asset.cached = true;
        asset.metadata = Object.assign({}, asset.metadata || {}, { cache_id: asset.cache_id });
        mediaPoolPersistAssets?.();
        try{ renderMediaPoolTray?.(); }catch(_e){}
        try{ renderMediaPoolProjectList?.(); }catch(_e){}
      }
    }
  }catch(_e){}
}


async function ensureLocalAudioCache(){
  // If the current local file already has a backend cache_id, reuse it.
  const cached = getCurrentLocalCachedSource();
  if (cached?.cacheId) return cached;

  const media = getLoadedMediaFile();
  if (!media) return null;

  progressStart('Extracting and caching local audio…');
  const fd = new FormData();
  fd.append('media', media, media.name);

  const res = await fetch(`${API_BASE}/api/local_cache_start`, { method:'POST', body: fd });
  if (!res.ok){
    const msg = await res.text().catch(()=> '');
    throw new Error(`Local cache HTTP ${res.status} ${msg}`);
  }
  const startResp = await res.json().catch(()=>({}));
  const jobId = startResp?.job_id;
  if (!jobId) throw new Error('No job_id returned from local cache job');
  setActiveBackendJob(jobId, 'local_cache');
  await pollJob(jobId);
  const data = await fetchJobResult(jobId);
  rememberLocalCacheFromBackend(data);
  // Keep the progress UI alive so the next Transcribe/Align job can start cleanly.
  // Do not call progressDone() here; this cache step is only phase 1 of the user's action.
  setStatusSafe('Local audio cached. Starting next step…');

  const src = getCurrentLocalCachedSource();
  if (!src?.cacheId){
    throw new Error('Local audio was cached, but no cache_id was returned by backend.');
  }
  return src;
}

// Pre-warm a local Media Pool asset's cache from a card button, without
// going through Transcribe/Align. Activates the asset briefly if it's not
// already current (so ensureLocalAudioCache has a file to upload), runs the
// cache job, stamps cache_id back onto the asset.
async function startLocalCache(asset){
  if (!asset) throw new Error('No asset.');
  const key = String(asset.media_pool_key || '');
  const file = (key && __mediaPoolLocalFiles?.get?.(key)) || asset.file || null;
  if (!file){
    throw new Error('This local file is no longer available in this browser session. Add it again, then cache it.');
  }
  // If this asset isn't the active one, briefly activate it so the existing
  // ensureLocalAudioCache() path (which uploads the File from currentMediaSource)
  // has the right bytes. After caching, leave currentMediaSource pointing at
  // this asset — it's the natural "you just cached this" state.
  const wasActive = (currentMediaSource?.mediaPoolKey === key);
  if (!wasActive){
    activateLocalMediaPoolAsset(asset);
  }
  try{
    await ensureLocalAudioCache();
    // rememberLocalCacheFromBackend already propagates cache_id onto the
    // matching pool asset, so we just need a final UI refresh.
    try{ renderMediaPoolTray?.(); }catch(_e){}
    try{ renderMediaPoolProjectList?.(); }catch(_e){}
    try{ renderNativeMediaPoolSource?.('local'); }catch(_e){}
    setStatusSafe(`Local cached: ${asset.title || asset.name || 'Local video'}`);
  } finally {
    progressDone(false);
  }
}

